/*
 * @method
 * @name aftermath#watchTrades
 * @description watches information on multiple trades made in a market
 * @see https://testnet.aftermath.finance/docs/#/CCXT/service%3A%3Ahandlers%3A%3Accxt%3A%3Astream%3A%3Atrades
 * @param {string} symbol unified market symbol of the market trades were made in
 * @param {int} [since] the earliest time in ms to fetch trades for
 * @param {int} [limit] the maximum number of trade structures to retrieve
 * @param {object} [params] extra parameters specific to the exchange API endpoint
 * @returns {object[]} a list of [trade structures]{@link https://docs.ccxt.com/?id=trade-structure}
 */
    pub async fn watch_trades(&mut self, mut symbol: Value, optional_args: &[Value]) -> Value {
        let mut since = get_arg(optional_args, 0, Value::Null);
        let mut limit = get_arg(optional_args, 1, Value::Null);
        let mut params = get_arg(optional_args, 2, Value::Map({
    let mut m = indexmap::IndexMap::new();
    m
}));
        self.load_markets(&[]).await;
        let mut market: Value = self.market(symbol.clone());
        symbol = get_value(&market, &Value::Str("symbol".to_string()));
        let mut topic: Value = add(&get_value(&market, &Value::Str("id".to_string())), &Value::Str("@trade".to_string()));
        let mut request: Value = Value::Map({
            let mut m = indexmap::IndexMap::new();
                m.insert("chId".to_string(), get_value(&market, &Value::Str("id".to_string())));
            m
        });
        let mut message: Value = self.extend(request.clone(), &[params.clone()]);
        let mut trades: Value = self.watch_public(Value::Str("trades".to_string()), topic.clone(), message.clone()).await;
        if is_true(&self.newUpdates) {
            limit = trades.get_limit(get_value(&market, &Value::Str("symbol".to_string())), limit.clone());
        }
        return self.filter_by_symbol_since_limit(trades.clone(), &[symbol.clone(), since.clone(), limit.clone(), Value::Bool(true)]);

    Value::Null
}

    pub fn handle_trade(&mut self, mut client: Value, mut message: Value) {
        //
        // {
        //     "amount": 0.1,
        //     "cost": 0.1,
        //     "datetime": "string",
        //     "fee": null,
        //     "id": "string",
        //     "order": "string",
        //     "price": 0.1,
        //     "side": null,
        //     "symbol": "string",
        //     "takerOrMaker": null,
        //     "timestamp": null,
        //     "type": "string"
        // }
        //
        let mut trade: Value = self.parse_trade(message.clone(), &[]);
        let mut symbol: Value = get_value(&trade, &Value::Str("symbol".to_string()));
        let mut market: Value = self.market(symbol.clone());
        if !is_true(&(Value::Bool(in_op(&self.trades, &symbol)))) {
            let mut limit: Value = self.safe_integer_k(self.options.clone(), "tradesLimit", &[Value::Int(1000)]);
            let mut stored = ArrayCache::new(limit.clone());
            add_element_to_object(&mut self.trades.clone(), &symbol, stored.clone());
        }
        let mut messageHash: Value = add(&get_value(&market, &Value::Str("id".to_string())), &Value::Str("@trade".to_string()));
        let mut trades: Value = get_value(&self.trades, &symbol);
        trades.append(trade.clone());
        add_element_to_object(&mut self.trades.clone(), &symbol, trades.clone());
        client.resolve(&[trades.clone(), messageHash.clone()]);
}

